const MAX_VAL = 100000;
const NEG_INF = -1; // Since all nums[i] >= 1, -1 serves as negative infinity for scores.

/**
 * Segment Tree for Range Maximum Query (RMQ) and Point Update (Max).
 * Indexed over the value range [1, MAX_VAL].
 */
class SegmentTree {
    constructor(size) {
        this.size = size;
        // Tree array size: 4 * size is usually safe.
        this.tree = new Array(4 * size + 1).fill(NEG_INF);
    }

    // Public update method: updates the value at index 'idx' to max(current_value, new_score)
    update(idx, score) {
        this._update(1, 1, this.size, idx, score);
    }

    _update(node, start, end, idx, score) {
        if (start === end) {
            this.tree[node] = Math.max(this.tree[node], score);
            return;
        }

        const mid = Math.floor((start + end) / 2);
        if (idx <= mid) {
            this._update(2 * node, start, mid, idx, score);
        } else {
            this._update(2 * node + 1, mid + 1, end, idx, score);
        }
        this.tree[node] = Math.max(this.tree[2 * node], this.tree[2 * node + 1]);
    }

    // Public query method: finds the maximum value in the range [L, R]
    query(L, R) {
        if (L > R) return NEG_INF;
        return this._query(1, 1, this.size, L, R);
    }

    _query(node, start, end, L, R) {
        // Range outside query range
        if (start > R || end < L) {
            return NEG_INF;
        }
        // Range fully within query range
        if (L <= start && end <= R) {
            return this.tree[node];
        }

        const mid = Math.floor((start + end) / 2);
        const p1 = this._query(2 * node, start, mid, L, R);
        const p2 = this._query(2 * node + 1, mid + 1, end, L, R);
        return Math.max(p1, p2);
    }
}


function solve(nums, k) {
    const N = nums.length;
    if (N === 0) return 0;

    // DP_UP[i]: Max score ending at i, with last step being an ascent (nums[j] < nums[i])
    const DP_UP = new Array(N).fill(0);
    // DP_DOWN[i]: Max score ending at i, with last step being a descent (nums[j] > nums[i])
    const DP_DOWN = new Array(N).fill(0);

    // ST_UP stores max(DP_UP[j]) indexed by nums[j], used for calculating DP_DOWN[i]
    const ST_UP = new SegmentTree(MAX_VAL);
    // ST_DOWN stores max(DP_DOWN[j]) indexed by nums[j], used for calculating DP_UP[i]
    const ST_DOWN = new SegmentTree(MAX_VAL);

    // Updates[t] stores pairs [score, value] scheduled to be inserted into STs when processing index t.
    // We use an array of arrays/lists for delayed updates.
    const Updates = Array(N).fill(0).map(() => []);

    let max_score = 0;

    for (let i = 0; i < N; i++) {
        const V = nums[i];

        // 1. Apply scheduled updates from j = i - k
        if (i >= k) {
            for (const update of Updates[i]) {
                const [score, value, type] = update;
                if (type === 'UP') {
                    ST_UP.update(value, score);
                } else { // type === 'DOWN'
                    ST_DOWN.update(value, score);
                }
            }
        }

        // 2. Calculate DP[i] using current state of STs (which only reflect j <= i-k)

        // Calculate DP_UP[i] (Ascent: requires predecessor j that ended with a descent)
        // Find max(DP_DOWN[j]) where nums[j] < V
        const M_down = ST_DOWN.query(1, V - 1);
        // Base case (length 1) is V. If M_down is NEG_INF, we take V.
        const score_up = V + Math.max(0, M_down);
        DP_UP[i] = score_up;


        // Calculate DP_DOWN[i] (Descent: requires predecessor j that ended with an ascent)
        // Find max(DP_UP[j]) where nums[j] > V
        const M_up = ST_UP.query(V + 1, MAX_VAL);
        // Base case (length 1) is V.
        const score_down = V + Math.max(0, M_up);
        DP_DOWN[i] = score_down;

        // Update overall maximum score
        max_score = Math.max(max_score, DP_UP[i], DP_DOWN[i]);


        // 3. Schedule updates for index i (These will be applied at i+k)
        if (i + k < N) {
            // Schedule DP_UP[i] to update ST_UP at index i+k
            Updates[i + k].push([DP_UP[i], V, 'UP']);
            // Schedule DP_DOWN[i] to update ST_DOWN at index i+k
            Updates[i + k].push([DP_DOWN[i], V, 'DOWN']);
        }
    }

    return max_score;
}

