fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }

    const MAX_VAL: i64 = 100000;
    // Since all nums[i] >= 1, we can use a very small number as negative infinity.
    const NEG_INF: i64 = -1e18 as i64;

    // ST_UP stores max(DP_UP[j]) indexed by nums[j]
    let mut st_up = SegmentTree::new(MAX_VAL as usize, NEG_INF);
    // ST_DOWN stores max(DP_DOWN[j]) indexed by nums[j]
    let mut st_down = SegmentTree::new(MAX_VAL as usize, NEG_INF);

    // Updates[t] stores pairs [score, value, type] scheduled to be inserted into STs when processing index t.
    // We use a tuple structure: (score, value, type_char)
    let mut updates: Vec<Vec<(i64, i64, char)>> = vec![vec![]; n];

    let mut max_score: i64 = 0;

    for i in 0..n {
        let v = nums[i];

        // 1. Apply scheduled updates from j = i - k
        // These updates originated from index j = i - k, and are now ready to be used for DP[i].
        if i >= k as usize {
            let i_k = i - k as usize;
            for &(score, value, type_) in updates[i_k].iter() {
