                    'U' => st_up.update(value, score),
                    'D' => st_down.update(value, score),
                    _ => unreachable!(),
                }
            }
        }

        // 2. Calculate DP[i] using current state of STs

        // DP_UP[i]: Ascent (predecessor j ended with descent, nums[j] > nums[i] is wrong, must be nums[j] < nums[i])
        // Requires predecessor j that ended with a descent (DP_DOWN[j]), where nums[j] < V.
        // Query ST_DOWN for values [1, V-1].
        let m_down = st_down.query(1, v - 1);
        // Base case (length 1) is V. If M_down is NEG_INF, we take V.
        let score_up = v + m_down.max(0);

        // DP_DOWN[i]: Descent (predecessor j ended with ascent, nums[j] > nums[i])
        // Requires predecessor j that ended with an ascent (DP_UP[j]), where nums[j] > V.
        // Query ST_UP for values [V+1, MAX_VAL].
        let m_up = st_up.query(v + 1, MAX_VAL);
        // Base case (length 1) is V.
        let score_down = v + m_up.max(0);

        // Update overall maximum score
        max_score = max_score.max(score_up).max(score_down);


        // 3. Schedule updates for index i (These will be applied at i+k)
        if i + k as usize < n {
            // Schedule DP_UP[i] to update ST_UP at index i+k
            updates[i + k as usize].push((score_up, v, 'U'));
            // Schedule DP_DOWN[i] to update ST_DOWN at index i+k
            updates[i + k as usize].push((score_down, v, 'D'));
        }
    }

    max_score
}

