    // DP_UP[i]: Max score ending at i, with last step being an ascent (nums[j] < nums[i])
    let mut dp_up = vec![0i64; n];
    // DP_DOWN[i]: Max score ending at i, with last step being a descent (nums[j] > nums[i])
    let mut dp_down = vec![0i64; n];

    // ST_UP stores max(DP_UP[j]) indexed by nums[j]. Used for calculating DP_DOWN[i].
    let mut st_up = SegmentTree::new(MAX_VAL);
    // ST_DOWN stores max(DP_DOWN[j]) indexed by nums[j]. Used for calculating DP_UP[i].
    let mut st_down = SegmentTree::new(MAX_VAL);

    // Updates[t] stores pairs [score, value, type] scheduled to be inserted into STs when processing index t.
    // Type: 1 for 'UP', 2 for 'DOWN'
    let mut updates: Vec<Vec<(i64, i64, i64)>> = vec![Vec::new(); n];

    let mut max_score = 0;

    for i in 0..n {
        let v = nums[i];
        let i_usize = i;

        // 1. Apply scheduled updates from j = i - k
        if i >= k as usize {
            let idx_to_apply = i - (k as usize);
            for &(score, value, type_flag) in &updates[idx_to_apply] {
