        let score_up = v + max(0, m_down);
        dp_up[i_usize] = score_up;

        // Calculate DP_DOWN[i] (Descent: requires predecessor j that ended with an ascent, nums[j] > V)
        // Find max(DP_UP[j]) where nums[j] > V
        let m_up = st_up.query(v + 1, MAX_VAL);
        // Base case (length 1) is V.
        let score_down = v + max(0, m_up);
        dp_down[i_usize] = score_down;

        // Update overall maximum score
        max_score = max(max_score, max(dp_up[i_usize], dp_down[i_usize]));


        // 3. Schedule updates for index i (These will be applied at i+k)
        let next_idx = i + k as usize;
        if next_idx < n {
            // Schedule DP_UP[i] to update ST_UP at index i+k
            updates[next_idx].push((dp_up[i_usize], v, 1));
            // Schedule DP_DOWN[i] to update ST_DOWN at index i+k
            updates[next_idx].push((dp_down[i_usize], v, 2));
        }
    }

    max_score
}

