use std::cmp::max;

const MAX_VAL: usize = 100000;
// Since all element values are >= 1, -1 serves as negative infinity for scores, 
// as a base score of 0 is used when no valid predecessor is found.
const NEG_INF: i64 = -1;

struct SegmentTree {
    size: usize,
    tree: Vec<i64>,
}

impl SegmentTree {
    fn new(size: usize) -> Self {
        // Tree size: 4 * size is safe. We use 1-based indexing internally.
        let tree_size = 4 * size + 1;
        SegmentTree {
            size,
            tree: vec![NEG_INF; tree_size],
        }
    }

    // Public update method: updates the value at index 'idx' to max(current_value, score)
    fn update(&mut self, idx: usize, score: i64) {
        if idx == 0 || idx > self.size { return; } // Should not happen given constraints
        self._update(1, 1, self.size, idx, score);
    }

    fn _update(&mut self, node: usize, start: usize, end: usize, idx: usize, score: i64) {
        if start == end {
            self.tree[node] = max(self.tree[node], score);
            return;
        }

        let mid = start + (end - start) / 2;
        if idx <= mid {
            self._update(2 * node, start, mid, idx, score);
        } else {
            self._update(2 * node + 1, mid + 1, end, idx, score);
        }
        self.tree[node] = max(self.tree[2 * node], self.tree[2 * node + 1]);
    }

    // Public query method: finds the maximum value in the range [L, R]
    fn query(&self, l: usize, r: usize) -> i64 {
        if l > r || l > self.size || r < 1 { return NEG_INF; }
        // Clamp range to valid bounds
        let l_clamped = l.max(1);
        let r_clamped = r.min(self.size);
        if l_clamped > r_clamped { return NEG_INF; }
        self._query(1, 1, self.size, l_clamped, r_clamped)
    }

    fn _query(&self, node: usize, start: usize, end: usize, l: usize, r: usize) -> i64 {
        // Range outside query range
        if start > r || end < l {
            return NEG_INF;
        }
        // Range fully within query range
        if l <= start && end <= r {
            return self.tree[node];
        }

        let mid = start + (end - start) / 2;
        let p1 = self._query(2 * node, start, mid, l, r);
        let p2 = self._query(2 * node + 1, mid + 1, end, l, r);
        max(p1, p2)
    }
}

fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    if n == 0 { return 0; }

